import org.springframework.beans.factory.annotation.Value;
import org.springframework.core.io.Resource;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.multipart.MultipartFile;

import javax.servlet.http.HttpServletResponse;
import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.Arrays;
import java.util.List;

@RestController
@RequestMapping("/api")
public class UserProfilePictureController {

    @Value("${upload.path}")
    private String uploadPath;

    @PostMapping("/profile-picture")
    public String uploadProfilePicture(@RequestParam("file") MultipartFile file, HttpServletResponse response) throws IOException {
        if (!isValidFile(file)) {
            return "Invalid file type";
        }

        Path filePath = generateFilePath();
        Files.copy(file.getInputStream(), filePath);

        String fileName = filePath.getFileName().toString();
        String fileUrl = "/uploads/" + fileName;

        response.sendRedirect(fileUrl);
        return fileUrl;
    }

    private boolean isValidFile(MultipartFile file) {
        List<String> allowedTypes = Arrays.asList("image/jpeg", "image/png", "image/gif");
        if (!allowedTypes.contains(file.getContentType())) {
            return false;
        }
        return true;
    }

    private Path generateFilePath() {
        String fileName = UUID.randomUUID().toString();
        File uploadDir = new File(uploadPath);
        if (!uploadDir.exists()) {
            uploadDir.mkdirs();
        }
        return Path.of(uploadPath, fileName + ".jpg");
    }
}